  ('disabled-10ced7e2-moex-00340', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-110-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '國家賠償法第2條規定，因公務員行為所產生之國家賠償責任，關於其成 立要件之敘述，下列何者錯誤？', '["人民之損害須與公務員之行為間具有因果關係", "公務員之行為僅限於積極之作為行為", "公務員之侵害行為須為行使公權力之行為", "公務員之不法侵害限於有故意或過失之行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:51+00:00", "source_pdf_sha1": "2f314779229e", "answer_pdf_sha1": "2390de2c8cd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00001', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '下列文句「」中的成語，何者運用最恰當？', '["他是「一絲不苟」的人，一向粗心大意，所以做事常常出紕漏", "我們專業貼心的居家清潔服務，保證讓您的居室「充棟汗牛」", "他努力克服各種挑戰，最終達成任務，便「志得意滿」的笑了", "您的言論真是「拋磚引玉」，為我將來的研究提供了不少幫助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00002', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '下列新聞標題，沒有出現贅詞的選項是：', '["冬季流感嚴峻 致死率果然唯恐上升", "樂透有望加碼 或許獎金可能加碼一億", "新春憾事 超商店員遭疑似酒駕嫌疑人撞傷", "消失的年夜飯 未收到預訂年夜飯者高達百人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
